/**
Define custom script which returns an array of actors in the following format
(function() {
    var content = execution.getVariables();
    var requestId = content.get('id');
    var requestIndex = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
    return [{
        "id": "managed/user/" + requestIndex.applicationOwner[0].id,
        "permissions": {
            "approve": true,
            "reject": true,
            "reassign": true,
            "modify": true,
            "comment": true
        }
    }];
})()
**/
(function() {
    logger.error("InSide Approver Node")
    var content = execution.getVariables();
    var requestId = content.get('id');
    var roleId = null;
    var users = [];

    try {
      var requestObj = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
        logger.error("Naren Wrokflow Logs requestObj  from Approval Node"+ requestObj )
      roleId = requestObj.request.custom.roleId;
        logger.error("Naren Wrokflow Logs Role ID from Approval Node"+ roleId )
    }
    catch (e) {
      failureReason = "Validation failed: Error reading request with id " + requestId;
    }
    try{
         logger.error("InSide Approver Node Line 16")
      var glossary = openidm.action('iga/governance/role/' + roleId +'/glossary', 'GET', {}, {})
     logger.error("Glossary Is "+glossary )
      let approversRole = glossary.approvers
      logger.error("Naren Workflow logs:Approval Node:  Approver Role is : "+ approversRole)
      var approversRoleId = approversRole.split("role/")[1];
        logger.error("Naren Workflow logs:Approval Node:  approversRoleId is : "+ approversRoleId)
    //   var params = {
    // '_queryFilter' : 'effectiveRoles._refResourceId eq "' + approversRoleId + '"'
    //   };
    //  var roleQueryResponse = openidm.query("managed/user", params, ["userName", "_id"]);

    var roleQueryResponse = openidm.query("managed/alpha_role/" + approversRoleId + "/members", {
    "_queryFilter": "true"
  }, ["_refResourceId"]);

    logger.error("Naren Workflow logs:Approval Node:  roleQueryResponse is"+ roleQueryResponse.result[0]._refResourceId)
        logger.error("Naren Workflow logs:Approval Node:  roleQueryResponse is"+ roleQueryResponse.result[1]._refResourceId)
        logger.error("Naren Workflow logs:Approval Node:  roleQueryResponse is"+ roleQueryResponse.result[2]._refResourceId)

     logger.error("Naren Workflow logs:Approval Node:  roleQueryResponse Length is"+ roleQueryResponse.result)
     logger.error("Naren Workflow logs:Approval Node:  roleQueryResponse is"+ roleQueryResponse.length)
     logger.error("Naren Workflow logs:Approval Node:  roleQueryResponse is"+ roleQueryResponse.result.length)
      for(var i = 0; i < roleQueryResponse.result.length; i++){
        var userId= roleQueryResponse.result[i]._refResourceId
         logger.error("Approver User ID is :: "+userId )
        // var userId = approvers[i];
        users.push({
          "id": "managed/user/"+userId, "permissions": {"approve": true, "reject": true, "forward": true, "modify": true, "comment": true}
        })

      }

    }
    catch (e){
      failureReason = "Validation failed: Error reading request with id " + requestId;
    }
    logger.error("Approvers are  "+users )

    if(users.length > 0){
      return users;
    }
    else {
      // default approver logic
    }
})()
